from dataclasses import dataclass, field
from typing import Optional
from enum import Enum
import hashlib, re, datetime

class VersionAlias(str, Enum):
    LATEST  = "latest"   # newest approved version
    STABLE  = "stable"   # current production
    CANARY  = "canary"   # receiving 5% of traffic
    BETA    = "beta"     # early-adopter programme
    LTS     = "lts"      # long-term support branch

@dataclass(frozen=True)
class ModelVersion:
    major: int
    minor: int
    patch: int
    pre: str = ""        # e.g. "dev", "rc.1"

    @classmethod
    def parse(cls, s: str) -> "ModelVersion":
        m = re.fullmatch(r"(\d+)\.(\d+)\.(\d+)(?:-(.+))?", s)
        if not m:
            raise ValueError(f"Invalid version string: {s!r}")
        return cls(int(m[1]), int(m[2]), int(m[3]), m[4] or "")

    def __str__(self) -> str:
        base = f"{self.major}.{self.minor}.{self.patch}"
        return f"{base}-{self.pre}" if self.pre else base

    def is_stable(self) -> bool:
        return self.pre == ""

    def bump_major(self) -> "ModelVersion":
        return ModelVersion(self.major + 1, 0, 0)

    def bump_minor(self) -> "ModelVersion":
        return ModelVersion(self.major, self.minor + 1, 0)

    def bump_patch(self) -> "ModelVersion":
        return ModelVersion(self.major, self.minor, self.patch + 1)

    def __lt__(self, other: "ModelVersion") -> bool:
        return (self.major, self.minor, self.patch) < (other.major, other.minor, other.patch)

@dataclass
class VersionRecord:
    version: ModelVersion
    artifact_sha256: str
    promoted_at: Optional[datetime.datetime] = None
    aliases: list[VersionAlias] = field(default_factory=list)
    compatibility: list[str] = field(default_factory=list)  # compatible app versions
    changelog: str = ""

class ModelRegistry:
    """In-memory registry; swap _records/_aliases for DB-backed storage."""

    def __init__(self) -> None:
        self._records: dict[str, VersionRecord] = {}
        self._aliases: dict[VersionAlias, str] = {}

    def register(self, version: ModelVersion, artifact_sha256: str,
                 compatibility: list[str], changelog: str) -> VersionRecord:
        key = str(version)
        if key in self._records:
            raise ValueError(f"Version {key} already registered (immutable).")
        rec = VersionRecord(version, artifact_sha256,
                            compatibility=compatibility, changelog=changelog)
        self._records[key] = rec
        return rec

    def promote(self, version: ModelVersion, alias: VersionAlias) -> None:
        key = str(version)
        if key not in self._records:
            raise KeyError(f"Unknown version {key}")
        # Remove alias from any current holder
        current = self._aliases.get(alias)
        if current and current in self._records:
            self._records[current].aliases = [
                a for a in self._records[current].aliases if a != alias
            ]
        self._aliases[alias] = key
        self._records[key].aliases.append(alias)
        if alias == VersionAlias.STABLE:
            self._records[key].promoted_at = datetime.datetime.utcnow()

    def rollback(self, alias: VersionAlias = VersionAlias.STABLE) -> VersionRecord:
        """Return the last stable version before the current one."""
        stable_key = self._aliases.get(alias)
        stable_ver = ModelVersion.parse(stable_key) if stable_key else None
        candidates = sorted(
            [r for r in self._records.values() if r.version.is_stable()],
            key=lambda r: r.version
        )
        for rec in reversed(candidates):
            if stable_ver is None or rec.version < stable_ver:
                self.promote(rec.version, alias)
                return rec
        raise RuntimeError("No previous stable version available for rollback.")

    def resolve(self, alias_or_version: str) -> VersionRecord:
        try:
            alias = VersionAlias(alias_or_version)
            key = self._aliases[alias]
        except (ValueError, KeyError):
            key = alias_or_version
        return self._records[key]

import anthropic, json, statistics, time

client = anthropic.Anthropic()

REGRESSION_SUITE = [
    {
        "id": "order_status_structured",
        "prompt": "What is the status of order #12345?",
        "expected_keywords": ["order", "status", "12345"],
        "max_latency_ms": 2000
    },
    {
        "id": "refund_policy",
        "prompt": "Can I return an item after 45 days?",
        "expected_keywords": ["return", "policy", "day"],
        "max_latency_ms": 1500
    },
    {
        "id": "product_recommendation",
        "prompt": "Suggest a laptop under $800 for a student.",
        "expected_keywords": ["laptop", "student", "recommend"],
        "max_latency_ms": 2500
    },
]

def run_regression(model_version: str, suite: list[dict]) -> dict:
    results = {"version": model_version, "passed": 0, "failed": 0, "latencies": []}
    for case in suite:
        t0 = time.monotonic()
        response = client.messages.create(
            model=model_version,
            max_tokens=256,
            messages=[{"role": "user", "content": case["prompt"]}]
        )
        elapsed_ms = (time.monotonic() - t0) * 1000
        text = response.content[0].text.lower()
        keyword_ok = all(kw in text for kw in case["expected_keywords"])
        latency_ok = elapsed_ms <= case["max_latency_ms"]
        if keyword_ok and latency_ok:
            results["passed"] += 1
        else:
            results["failed"] += 1
            results.setdefault("failures", []).append({
                "id": case["id"], "keyword_ok": keyword_ok,
                "latency_ok": latency_ok, "latency_ms": round(elapsed_ms)
            })
        results["latencies"].append(elapsed_ms)
    results["p50_ms"] = round(statistics.median(results["latencies"]))
    results["p99_ms"] = round(sorted(results["latencies"])[
        max(0, int(len(results["latencies"]) * 0.99) - 1)
    ])
    return results

def compare_versions(baseline: str, candidate: str) -> bool:
    b = run_regression(baseline, REGRESSION_SUITE)
    c = run_regression(candidate, REGRESSION_SUITE)
    regression = c["failed"] > b["failed"] or c["p99_ms"] > b["p99_ms"] * 1.15
    print(f"Baseline {baseline}: {b['passed']}/{len(REGRESSION_SUITE)} pass, p99={b['p99_ms']}ms")
    print(f"Candidate {candidate}: {c['passed']}/{len(REGRESSION_SUITE)} pass, p99={c['p99_ms']}ms")
    if regression:
        print("REGRESSION DETECTED — blocking promotion")
    return not regression
